from lxml import etree

def process_soap_request(soap_request):
    # Parse the SOAP request and validate
    dic = {'http://schemas.xmlsoap.org/soap/envelope/': 'soapenv'}
    root = etree.fromstring(soap_request)
    validation_result = root.docinfo.validate
    
    if not validation_result:
        raise Exception("Invalid DTD")
    
    # Extract SOAP body
    body = root.xpath('//soapenv:Body', namespaces=dic)
    
    if len(body) == 0:
        raise Exception("Body not found in request")
    
    return etree.tostring(body[0], pretty_print=True, encoding='unicode')